class ScreenFade {
    private overlay: cc.LayerColor;
    private parent: cc.Node;

    constructor(parent: cc.Node) {
        this.parent = parent;
        this.overlay = new cc.LayerColor(cc.color(0, 0, 0, 0));
        this.overlay.setContentSize(cc.director.getWinSize());
        this.overlay.setLocalZOrder(9999);
        this.parent.addChild(this.overlay);
    }

    fadeOut(duration: number, callback: () => void): void {
        this.overlay.setOpacity(0);
        this.overlay.runAction(
            cc.sequence(
                cc.fadeTo(duration, 255),
                cc.callFunc(callback)
            )
        );
    }

    fadeIn(duration: number): void {
        this.overlay.setOpacity(255);
        this.overlay.runAction(cc.fadeTo(duration, 0));
    }
}

// Usage:
const fade = new ScreenFade(this);
fade.fadeOut(0.5, () => {
    // Load next scene
    cc.director.runScene(new NextScene());
    fade.fadeIn(0.5);
});
```

The overlay starts fully transparent (alpha 0). `fadeOut` animates opacity to 255 (black), then triggers the callback. `fadeIn` animates from 255 back to 0. Using `cc.fadeTo` with `cc.sequence` and `cc.callFunc` chains the actions smoothly.

