class TabbedInterface extends cc.Layer {
    private multiplex: cc.LayerMultiplex;
    private tabNames: string[];
    private currentTab: number = 0;

    constructor(tabs: { name: string; color: cc.Color }[]) {
        super();
        this.tabNames = tabs.map(t => t.name);

        const panels = tabs.map(t => new TabPanel(t.color, t.name));
        this.multiplex = new cc.LayerMultiplex(...panels);
        this.addChild(this.multiplex);

        this.createTabButtons(tabs);
    }

    private createTabButtons(tabs: { name: string; color: cc.Color }[]): void {
        const winSize = cc.director.getWinSize();
        const tabWidth = winSize.width / tabs.length;

        tabs.forEach((tab, index) => {
            const btn = new cc.LayerColor(
                cc.color(80, 80, 80, 255),
                tabWidth - 4, 40
            );
            btn.setPosition(index * tabWidth + 2, winSize.height - 44);
            this.addChild(btn, 10);

            const label = new cc.LabelTTF(tab.name, 'Arial', 16);
            label.setPosition(tabWidth / 2, 20);
            btn.addChild(label);
        });
    }

    switchTab(index: number): void {
        if (index === this.currentTab) return;
        if (index < 0 || index >= this.tabNames.length) return;

        this.multiplex.switchTo(index);
        this.currentTab = index;
    }
}

// Usage:
const tabbed = new TabbedInterface([
    { name: 'Inventory', color: cc.color(40, 60, 80, 255) },
    { name: 'Stats',     color: cc.color(60, 40, 80, 255) },
    { name: 'Skills',    color: cc.color(80, 60, 40, 255) }
]);
scene.addChild(tabbed);
tabbed.switchTab(1);
```

Each tab is a `TabPanel` (extending `cc.LayerColor`) managed by `cc.LayerMultiplex`. Tab buttons are `cc.LayerColor` rectangles positioned at the top. `switchTab` delegates to `multiplex.switchTo` while tracking the active index.

