class LoadingScreen extends cc.Layer {
    private barBg: cc.LayerColor;
    private barFill: cc.LayerGradient;
    private barWidth: number;
    private barHeight: number;
    private label: cc.LabelTTF;

    constructor() {
        super();
        this.init();
    }

    init(): boolean {
        const winSize = cc.director.getWinSize();

        // Dark background
        const bg = new cc.LayerColor(cc.color(15, 15, 25, 255));
        this.addChild(bg, 0);

        // Progress bar dimensions
        this.barWidth = winSize.width * 0.6;
        this.barHeight = 24;
        const barX = (winSize.width - this.barWidth) / 2;
        const barY = winSize.height / 2 - this.barHeight / 2;

        // Bar background (dark gray)
        this.barBg = new cc.LayerColor(
            cc.color(40, 40, 50, 255),
            this.barWidth, this.barHeight
        );
        this.barBg.setPosition(barX, barY);
        this.addChild(this.barBg, 1);

        // Gradient fill (green to bright green)
        this.barFill = new cc.LayerGradient(
            cc.color(0, 180, 80, 255),
            cc.color(0, 255, 120, 255),
            cc.p(1, 0)
        );
        this.barFill.changeWidthAndHeight(0, this.barHeight);
        this.barFill.setPosition(barX, barY);
        this.addChild(this.barFill, 2);

        // Loading label
        this.label = new cc.LabelTTF('Loading... 0%', 'Arial', 18);
        this.label.setPosition(winSize.width / 2, barY + this.barHeight + 30);
        this.addChild(this.label, 3);

        return true;
    }

    setProgress(percent: number): void {
        const clamped = Math.max(0, Math.min(100, percent));
        const fillWidth = (clamped / 100) * this.barWidth;
        this.barFill.changeWidth(fillWidth);
        this.label.setString('Loading... ' + Math.floor(clamped) + '%');
    }
}

// Usage:
const loading = new LoadingScreen();
