const sky = new cc.LayerGradient(
    cc.color(135, 206, 250, 255),
    cc.color(25, 25, 112, 255),
    cc.p(0, -1)
);
this.addChild(sky, -1);

this.schedule(() => {
    sky.setStartColor(cc.color(
        Math.floor(Math.random() * 255),
        Math.floor(Math.random() * 255),
        Math.floor(Math.random() * 255)
    ));
}, 1.0);
```

Use `this.schedule` which ties to node lifecycle, and `Math.floor` for integer colors.

